// V1 source list — replace this node with a Google Sheets "Get Rows" node
// once the business-team sheet is wired (columns: enabled, name, url, language, topics).
// Each item below becomes one branch downstream.
return [
  {
    json: {
      enabled: true,
      name: 'BBC News',
      url: 'https://www.bbc.com/news',
      language: 'en',
      // regex matched against discovered links — keeps only real article URLs
      article_url_pattern: '^https://www\\.bbc\\.com/news/articles/[a-z0-9]+$',
      topics: ['breaking']
    }
  },
  {
    json: {
      enabled: true,
      name: 'Al Jazeera',
      url: 'https://www.aljazeera.com/news/',
      language: 'en',
      article_url_pattern: '^https://www\\.aljazeera\\.com/news/\\d{4}/\\d{1,2}/\\d{1,2}/[a-z0-9-]+$',
      topics: ['breaking']
    }
  }
].filter(i => i.json.enabled);

// For each source: keep only links matching its article_url_pattern,
// dedupe, cap at 10 article URLs to keep call volume sane for V1.
const out = [];
for (const item of $input.all()) {
  const links = item.json?.data?.links || [];
  const src = item.json; // includes our merged source row from the previous node? No — http response loses it.
  // Recover source context from the paired-item input:
  const source = $('Source list (replace with Google Sheets)').itemMatching(item.pairedItem.item).json;
  const re = new RegExp(source.article_url_pattern);
  const seen = new Set();
  for (const u of links) {
    if (re.test(u) && !seen.has(u)) {
      seen.add(u);
      out.push({
        json: {
          source_name: source.name,
          source_url: source.url,
          language: source.language,
          topics: source.topics,
          article_url: u
        }
      });
      if (seen.size >= 10) break;
    }
  }
}
return out;

