// Shape the Firecrawl response into a flat row ready for TTS / dedupe / broadcast.
const out = [];
for (const item of $input.all()) {
  const j = item.json?.data?.json || {};
  const ctx = $('Per article').itemMatching(item.pairedItem.item).json;
  if (!j.headline || !j.body) continue; // skip failures
  out.push({
    json: {
      source_name: ctx.source_name,
      source_url: ctx.source_url,
      article_url: ctx.article_url,
      language: ctx.language,
      topics: ctx.topics,
      headline: j.headline,
      dek: j.dek || null,
      body: j.body,
      published_date: j.published_date || null,
      // hash for idempotency in the deliveries table later
      fingerprint: require('crypto').createHash('sha256').update(ctx.article_url).digest('hex').slice(0, 16),
      scraped_at: new Date().toISOString()
    }
  });
}
return out;
